+
+  it("notifies registered write listeners with committed runtime snapshots", () => {
+    const seen: Array<{ configPath: string; runtimeConfig: OpenClawConfig }> = [];
+    const unsubscribe = registerRuntimeConfigWriteListener((event) => {
+      seen.push({
